<template><div class="page-content"><PageHeader eyebrow="Governance" title="Approvals" description="审核 Production 发布申请并保留完整审批轨迹"><el-button :loading="loading" @click="load">刷新</el-button></PageHeader><div class="metrics"><MetricCard title="待审批" :value="pendingCount" icon="◷" tone="blue"/><MetricCard title="已通过" :value="approvedCount" icon="✓" tone="green"/><MetricCard title="已拒绝" :value="rejectedCount" icon="×" tone="red"/><MetricCard title="全部记录" :value="total" icon="▤"/></div><section class="surface table-card"><div class="toolbar"><div><el-select v-model="status" style="width:130px"><el-option label="全部状态" value=""/><el-option v-for="s in statuses" :key="s" :label="s" :value="s"/></el-select><el-select v-model="environment" style="width:130px"><el-option label="全部环境" value=""/><el-option label="Production" value="prod"/><el-option label="Staging" value="staging"/></el-select></div><span>{{total}} approval records</span></div><el-skeleton :loading="loading" animated :rows="7"><el-table v-if="items.length" :data="items"><el-table-column label="申请" min-width="210"><template #default="{row}"><div class="application"><span>{{(row.application_name||'A')[0].toUpperCase()}}</span><div><b>{{row.application_name||`Application #${row.application_id}`}}</b><small>{{row.applicant}} 提交</small></div></div></template></el-table-column><el-table-column label="目标环境" width="130"><template #default="{row}"><span class="env">{{row.environment}}</span><small>{{row.namespace}}</small></template></el-table-column><el-table-column label="发布镜像" min-width="220"><template #default="{row}"><code>{{row.image}}</code><small>{{row.git_commit?.slice(0,8)||row.git_branch}}</small></template></el-table-column><el-table-column label="状态" width="120"><template #default="{row}"><StatusBadge :status="statusTone(row.status)" :label="row.status"/></template></el-table-column><el-table-column label="审批人" width="120"><template #default="{row}">{{row.approver||'—'}}</template></el-table-column><el-table-column label="申请时间" width="170"><template #default="{row}">{{format(row.created_at)}}</template></el-table-column><el-table-column label="操作" width="200" fixed="right"><template #default="{row}"><template v-if="row.status==='Pending'"><el-button link type="primary" :loading="actingId===row.id" @click="approve(row)">通过</el-button><el-button link type="danger" :loading="actingId===row.id" @click="reject(row)">拒绝</el-button></template><el-button v-if="row.pipeline_run_name" link @click="$router.push(`/pipelines/${row.pipeline_run_name}`)">Pipeline</el-button><span v-if="row.status!=='Pending'&&!row.pipeline_run_name" class="processed">已处理</span></template></el-table-column></el-table><EmptyState v-else title="没有审批记录" description="当用户向需要审批的 Production 环境发布时，申请会出现在这里。" icon="✓"/></el-skeleton><footer><el-pagination v-model:current-page="page" :page-size="pageSize" layout="prev,pager,next" :total="total"/></footer></section></div></template>
<script setup lang="ts">import{computed,onMounted,ref,watch}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{approvalApi}from'../api/approval';import type{Approval}from'../types';import PageHeader from'../components/common/PageHeader.vue';import MetricCard from'../components/common/MetricCard.vue';import StatusBadge from'../components/common/StatusBadge.vue';import EmptyState from'../components/common/EmptyState.vue';const items=ref<Approval[]>([]),total=ref(0),page=ref(1),pageSize=20,status=ref(''),environment=ref(''),loading=ref(false),actingId=ref(0),statuses=['Pending','Approved','Rejected'];const pendingCount=computed(()=>items.value.filter(i=>i.status==='Pending').length),approvedCount=computed(()=>items.value.filter(i=>i.status==='Approved').length),rejectedCount=computed(()=>items.value.filter(i=>i.status==='Rejected').length);async function load(){loading.value=true;try{const data=await approvalApi.list({page:page.value,pageSize,status:status.value||undefined,environment:environment.value||undefined});items.value=data.items;total.value=data.total}finally{loading.value=false}}async function approve(item:Approval){const{value}=await ElMessageBox.prompt('可填写审批意见','通过 Production 发布',{inputPlaceholder:'同意发布'});actingId.value=item.id;try{await approvalApi.approve(item.id,value);ElMessage.success('审批通过，PipelineRun 已启动');load()}finally{actingId.value=0}}async function reject(item:Approval){const{value}=await ElMessageBox.prompt('请填写拒绝原因','拒绝发布',{inputValidator:v=>!!v||'拒绝原因不能为空',type:'warning'});actingId.value=item.id;try{await approvalApi.reject(item.id,value);ElMessage.success('审批已拒绝');load()}finally{actingId.value=0}}const statusTone=(s:string)=>s==='Approved'?'Succeeded':s==='Rejected'?'Failed':'Pending',format=(v:string)=>new Date(v).toLocaleString('zh-CN',{hour12:false});watch([page,status,environment],load);onMounted(load)

</script>
<style scoped>.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:14px}.table-card{overflow:hidden}.toolbar{height:58px;padding:0 16px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--border-soft)}.toolbar>div{display:flex;gap:8px}.toolbar>span{font-size:12px;color:var(--muted)}.application{display:flex;align-items:center;gap:9px}.application>span{width:31px;height:31px;display:grid;place-items:center;border-radius:8px;background:var(--primary-soft);color:#978bed;font-size:13px;font-weight:700}.application b,.application small,td small,td code{display:block}.application b{font-size:13px}small{font-size:12px;color:var(--muted);margin-top:4px}.env{display:inline-block;padding:3px 6px;border-radius:5px;background:rgba(231,99,111,.1);color:#e87d86;font-size:12px;text-transform:uppercase}code{font-size:12px;color:#9da7b8}.processed{font-size:12px;color:var(--subtle)}footer{display:flex;justify-content:flex-end;padding:12px 16px;border-top:1px solid var(--border-soft)}</style>
